CREATE OR REPLACE FUNCTION fpa_com_month_initial (ai_month_number integer ) RETURNS varchar AS $body$
DECLARE

ls_return varchar(400);

BEGIN
  case ai_month_number
   when '1' then
     ls_return := 'ม.ค.';
   when '2' then
     ls_return := 'ก.พ.';
    when '3' then
   ls_return := 'มี.ค.';
   when '4' then
   ls_return := 'เม.ย.';
   when '5' then
   ls_return := 'พ.ค.';
   when '6' then
   ls_return := 'มิ.ย.';
   when '7' then
   ls_return := 'ก.ค.';
   when '8' then
   ls_return := 'ส.ค.';
   when '9' then
   ls_return := 'ก.ย.';
   when '10' then
   ls_return := 'ต.ค.';
   when '11' then
   ls_return := 'พ.ย.';
   when '12' then
   ls_return := 'ธ.ค.';
   else
   ls_return := '<ไม่ระบุ>';
  end case;

  return ls_return;
Exception
 when others then CALL spa_dberror('FPA_COM_MONTH_INITIAL');

END;
$body$
LANGUAGE PLPGSQL
